mapper.select:
SELECT C.CUST_ID AS custId, P.OPEN_STATUS AS status, P.OPEN_DATE AS openDate, C.RECEIPT_DT AS receiptDate, C.CANCELL_DT AS cancellationDate, C.JOIN_DATE AS authenticatedDate, C.CUST_NAME AS custName, C.REP_NAME AS repName, C.CUST_TYPE AS custType, C.CUST_KIND AS custKind, C.ADDR AS addr, C.ADDR_DETAIL AS addrDetail, C.HP_NO AS hpNo, C.HP_CARRIER AS hpCarrier, C.TEL_NO AS telNo, C.EMAIL AS email, C.COUNSELOR_NAME AS counselorName, C.DEPT_ID AS deptId, C.ASSIGNED_USER_ID AS assignedUserId, C.REMARK AS remark, C.USE_YN AS useYn, C.CREATOR_ID AS creatorId, C.CREATED_AT AS createdAt, C.UPDATED_AT AS updatedAt, CREATOR.USER_NAME AS creatorName, ASSIGNED.USER_NAME AS assignedUserName, ST.CODE_NAME AS statusName, HC.CODE_NAME AS hpCarrierName, CT.CODE_NAME AS custTypeName, CK.CODE_NAME AS custKindName, P.PROD_NAME AS prodName, COALESCE(PT.CODE_NAME, P.PROD_GB) AS prodType, P.STB_TYPE AS setInfo, P.SUBSCRIPTION_NO AS subscription_no, /* 가입번호: TB_CUST_PRODUCT.SUBSCRIPTION_NO */ P.CONTRACT_PERIOD AS contractPeriod, G.GIFT_NAME AS gift, G.GIFT_AMOUNT AS amount, G.ADD_DEPOSIT_AMOUNT AS addDeposit, COALESCE(PS.CODE_NAME, G.PAY_SOURCE) AS paySource, G.PAY_DONE_DATE AS payDone FROM TB_CUSTOMER C LEFT JOIN TB_USER CREATOR ON C.CREATOR_ID = CREATOR.USER_ID LEFT JOIN TB_USER ASSIGNED ON C.ASSIGNED_USER_ID = ASSIGNED.USER_ID LEFT JOIN ( SELECT P1.CUST_ID, P1.PROD_NAME, P1.PROD_GB, P1.STB_TYPE, P1.CONTRACT_PERIOD, P1.SUBSCRIPTION_NO, P1.OPEN_DATE, P1.CANCEL_DATE, P1.OPEN_STATUS FROM TB_CUST_PRODUCT P1 INNER JOIN ( SELECT CUST_ID, MIN(PROD_ID) AS MIN_PROD_ID FROM TB_CUST_PRODUCT WHERE (USE_YN IS NULL OR USE_YN = 'Y') GROUP BY CUST_ID ) FP ON P1.CUST_ID = FP.CUST_ID AND P1.PROD_ID = FP.MIN_PROD_ID WHERE (P1.USE_YN IS NULL OR P1.USE_YN = 'Y') ) P ON P.CUST_ID = C.CUST_ID LEFT JOIN ( SELECT G1.CUST_ID, G1.GIFT_NAME, G1.GIFT_AMOUNT, G1.ADD_DEPOSIT_AMOUNT, G1.PAY_SOURCE, G1.PAY_DONE_DATE FROM TB_CUST_GIFT G1 INNER JOIN ( SELECT CUST_ID, MIN(GIFT_ID) AS MIN_GIFT_ID FROM TB_CUST_GIFT WHERE GIFT_GB = 'GENERAL' GROUP BY CUST_ID ) FG ON G1.CUST_ID = FG.CUST_ID AND G1.GIFT_ID = FG.MIN_GIFT_ID WHERE G1.GIFT_GB = 'GENERAL' ) G ON G.CUST_ID = C.CUST_ID LEFT JOIN TB_COMMON_CODE ST ON ST.GROUP_CODE = 'CUST_STATUS' AND ST.CODE_VALUE = P.OPEN_STATUS AND (ST.USE_YN IS NULL OR ST.USE_YN = 'Y') LEFT JOIN TB_COMMON_CODE HC ON HC.GROUP_CODE = 'COMPANY_CODE' AND HC.CODE_VALUE = C.HP_CARRIER AND (HC.USE_YN IS NULL OR HC.USE_YN = 'Y') LEFT JOIN TB_COMMON_CODE CT ON CT.GROUP_CODE = 'CUST_TYPE' AND CT.CODE_VALUE = C.CUST_TYPE AND (CT.USE_YN IS NULL OR CT.USE_YN = 'Y') LEFT JOIN TB_COMMON_CODE CK ON CK.GROUP_CODE = 'CUST_KIND' AND CK.CODE_VALUE = C.CUST_KIND AND (CK.USE_YN IS NULL OR CK.USE_YN = 'Y') LEFT JOIN TB_COMMON_CODE PT ON PT.GROUP_CODE = 'PROD_COMB_GB' AND PT.CODE_VALUE = P.PROD_GB AND (PT.USE_YN IS NULL OR PT.USE_YN = 'Y') LEFT JOIN TB_COMMON_CODE PS ON PS.GROUP_CODE = 'PAY_SOURCE' AND PS.CODE_VALUE = G.PAY_SOURCE AND (PS.USE_YN IS NULL OR PS.USE_YN = 'Y') WHERE C.USE_YN = 'Y' AND C.CUST_KIND = COALESCE(#{custKind}, 'INDIVIDUAL')
AND C.ASSIGNED_USER_ID IN ( SELECT USER_ID FROM TB_USER WHERE DEPT_ID = #{filterDeptId} AND (USE_YN IS NULL OR USE_YN = 'Y') )
AND C.ASSIGNED_USER_ID = #{filterUserId}
AND 1=0
AND C.DEPT_ID = #{searchDeptId} AND C.ASSIGNED_USER_ID = #{searchAssignedUserId} AND C.CUST_NAME LIKE CONCAT('%', #{searchCustName}, '%') AND ASSIGNED.USER_NAME LIKE CONCAT('%', #{searchCounselorName}, '%') AND P.OPEN_STATUS = #{searchStatus} AND C.HP_CARRIER = #{searchHpCarrier}
AND C.RECEIPT_DT >= #{searchCreatedAtFrom} AND C.RECEIPT_DT <= #{searchCreatedAtTo}
AND P.OPEN_DATE >= #{searchCreatedAtFrom} AND P.OPEN_DATE <= #{searchCreatedAtTo}
AND C.JOIN_DATE >= #{searchCreatedAtFrom} AND C.JOIN_DATE <= #{searchCreatedAtTo}
AND P.CANCEL_DATE >= #{searchCreatedAtFrom} AND P.CANCEL_DATE <= #{searchCreatedAtTo}
AND C.CREATED_AT >= #{searchCreatedAtFrom} AND C.CREATED_AT <= CONCAT(#{searchCreatedAtTo}, ' 23:59:59')
ORDER BY C.CREATED_AT DESC LIMIT #{limit}

mapper.insert:
INSERT INTO TB_CUSTOMER (
STATUS, CUST_NAME, REP_NAME, CUST_TYPE, CUST_KIND, SSN_ENC, BIZ_NO, CORP_NO, FOREIGNER_REG_NO,
ZIP_CODE, ADDR, ADDR_DETAIL, TEL_NO, HP_NO, HP_CARRIER, EMAIL,
CUST_AUTH_TYPE, CUST_AUTH_VAL, COUNSELOR_NAME, DEPT_ID, ASSIGNED_USER_ID, REMARK, VOUCHER_RETURN_YN, INSTALL_SCHED_DT, OPEN_DATE, RECEIPT_DT, CANCELL_DT, JOIN_DATE, USE_YN, CREATOR_ID
) VALUES (
COALESCE(#{status}, 'RECEIPT'), #{custName}, #{repName}, #{custType}, COALESCE(#{custKind}, 'INDIVIDUAL'),
#{ssnEnc}, #{bizNo}, #{corpNo}, #{foreignerRegNo}, #{zipCode}, #{addr}, #{addrDetail},
#{telNo}, #{hpNo}, #{hpCarrier}, #{email}, #{custAuthType}, #{custAuthVal},
#{counselorName}, #{deptId}, #{assignedUserId}, #{remark}, COALESCE(#{voucherReturnYn}, 'N'), #{installSchedDt}, #{openDate}, #{receiptDate}, #{cancellationDate}, #{authenticatedDate}, COALESCE(#{useYn}, 'Y'), #{creatorId}
)
